class GlobalStateValue(typing.TypedDict):
    """Shape of global_state state key values"""
    _owner: str
    _totalStaked: bytes
    _rewardRatePerSecond: bytes
    _totalRewardsPaid: bytes
    _stakerCount: bytes
    _lockDuration: bytes

class TokenStakingV2State:
    """Methods to access state for the current TokenStakingV2 app"""

